    local children = pack:GetChildren()
    for i, child in ipairs(children) do
        if child.Name == "RF/" .. plainName then
            local target = children[i+1]
            if target and target.ClassName == "RemoteFunction" and target.Name:match("^RF/[0-9a-f]+$") then
                print("[Bypass] " .. plainName .. " => " .. target.Name:sub(1,15) .. "...")
                return target
            end
        end
    end
    warn("🚨 FATAL: Gagal bypass " .. plainName)
    return nil
end

